// prefixSegment is a single clickable segment in the breadcrumb.
type prefixSegment struct {
	Label  string
	Prefix string
}

// prefixSegments converts a prefix like "a/b/c/" into clickable breadcrumb segments.
func prefixSegments(prefix string) []prefixSegment {
	parts := strings.Split(strings.TrimSuffix(prefix, "/"), "/")
	segs := make([]prefixSegment, 0, len(parts))
	acc := ""
	for _, p := range parts {
		if p == "" {
			continue
		}
		acc += p + "/"
		segs = append(segs, prefixSegment{Label: p, Prefix: acc})
	}
	return segs
}

